import {{ Injectable }} from '@nestjs/common';
import {{ AuthService }} from './models/auth.model';
import {{ AuthServiceRepository }} from './repositories/auth.repository';

@Injectable()
export class AuthServiceService {{
  constructor(
    private readonly repository: AuthServiceRepository,
  ) {{}}

  async findAll(): Promise<AuthService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<AuthService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<AuthService>): Promise<AuthService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<AuthService>): Promise<AuthService> {{
    return this.repository.update(id, data);
  }}
}}
